class Playground {
    async run(inputs) {
        // 1. Parse inputs
        const nums = JSON.parse(inputs[0]);
        const target = parseInt(inputs[1]);

        // 2. Initialize Data Structures
        await this.array.init(nums);
        await this.vars.init([
            ["low", 0],
            ["high", nums.length - 1],
            ["mid", "-"],
            ["status", "Initializing"]
        ]);

        this.log(`Starting Binary Search for target: ${target}`);
        await this.await();

        let low = 0;
        let high = nums.length - 1;

        while (low <= high) {
            // Update variables
            const mid = Math.floor(low + (high - low) / 2);
            this.vars.put("low", low);
            this.vars.put("high", high);
            this.vars.put("mid", mid);
            this.vars.put("status", "Calculating Mid");

            // Visualization: Clear previous highlights and show current search range
            for (let i = 0; i < nums.length; i++) {
                this.array.highlight(i, "transparent");
            }
            this.array.highlightRange(low, high, "rgba(0, 150, 255, 0.2)");
            this.array.highlight(mid, "orange");

            this.log(`Range [${low}, ${high}]. Mid index: ${mid}, Mid value: ${this.array.get(mid)}`);
            await this.await();

            const midVal = this.array.get(mid);

            if (midVal === target) {
                // Target Found
                this.array.highlight(mid, "#4CAF50"); // Green
                this.vars.put("status", "Target Found!");
                this.log(`Success: Target ${target} found at index ${mid}`);
                await this.await();
                return mid;
            } 

            if (midVal < target) {
                // Target is in the right half
                this.log(`${midVal} < ${target}. Ignoring the left half (moving low).`);
                this.vars.put("status", "Searching Right");
                low = mid + 1;
            } else {
                // Target is in the left half
                this.log(`${midVal} > ${target}. Ignoring the right half (moving high).`);
                this.vars.put("status", "Searching Left");
                high = mid - 1;
            }

            await this.await();
        }

        // Target Not Found
        this.log(`Target ${target} was not found in the array.`);
        this.vars.put("status", "Not Found");
        this.vars.put("low", low);
        this.vars.put("high", high);
        this.vars.put("mid", "-");

        // Cleanup highlights
        for (let i = 0; i < nums.length; i++) {
            this.array.highlight(i, "rgba(255, 0, 0, 0.1)");
        }

        await this.await();
        return -1;
    }
}
